  <!-- En-tête épuré et compact -->
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-medical-fill" style="color: #0ea5e9;"></i> Rédaction d'une fiche de poste</h3>
      <p style="margin: 2px 0 0 0; color: #64748b; font-size: 13px;">Remplissez les critères requis pour diffuser votre annonce d'emploi en Tunisie.</p>
    </div>
  </div>

  <!-- Intégration de la notification flash professionnelle temporisée (si configurée) -->
  @if (notification.show) {
    <div class="toast-notification" [ngClass]="notification.type">
      <div class="toast-content">
        <span class="toast-icon">{{ notification.type === 'success' ? '✅' : '❌' }}</span>
        <p class="toast-message">{{ notification.message }}</p>
      </div>
    </div>
  }

  <!-- 📊 DISPOSITION DOUBLE PANNEAU SANS SCROLL -->
  <form (ngSubmit)="onPublish($event)" class="job-split-layout">
    
    <!-- ================= PANNEAU GAUCHE : CRITÈRES ET OPTIONS ================= -->
    <div class="job-panel-card">
      <div class="panel-inner-title"><i class="bi bi-sliders"></i> Critères de l'offre</div>
      
      <div class="compact-form-grid">
        <!-- Intitulé du poste -->
        <div class="form-group-compact span-all">
          <label for="title">Intitulé du poste *</label>
          <input type="text" id="title" name="title" [(ngModel)]="job.title" placeholder="Ex: Développeur Angular Senior" required>
        </div>
        
        <!-- Localisation -->
        <div class="form-group-compact span-all">
          <label for="location">Localisation *</label>
          <input type="text" id="location" name="location" [(ngModel)]="job.location" placeholder="Ex: Les Berges du Lac, Tunis" required>
        </div>

        <!-- Type de contrat -->
        <div class="form-group-compact">
          <label for="contract_type">Type de contrat</label>
          <select id="contract_type" name="contract_type" [(ngModel)]="job.contract_type" class="form-select-compact">
            <option value="CDI">CDI</option>
            <option value="CDD">CDD</option>
            <option value="SIVP">SIVP / Stage</option>
            <option value="Freelance">Freelance</option>
          </select>
        </div>

        <!-- Mode de travail -->
        <div class="form-group-compact">
          <label for="workplace_type">Mode de travail</label>
          <select id="workplace_type" name="workplace_type" [(ngModel)]="job.workplace_type" class="form-select-compact">
            <option value="Présentiel">Présentiel</option>
            <option value="Hybride">Hybride</option>
            <option value="Télétravail">Télétravail à 100%</option>
          </select>
        </div>

        <!-- Salaire indicatif -->
        <div class="form-group-compact">
          <label for="salary">Salaire indicatif (Optionnel)</label>
          <input type="text" id="salary" name="salary" [(ngModel)]="job.salary" placeholder="Ex: 1500 - 2200 DT">
        </div>

        <!-- Niveau d'expérience -->
        <div class="form-group-compact">
          <label for="experience_level">Expérience requise</label>
          <select id="experience_level" name="experience_level" [(ngModel)]="job.experience_level" class="form-select-compact">
            <option value="Junior (0-2 ans)">Junior (0-2 ans)</option>
            <option value="Intermédiaire (2-5 ans)">Intermédiaire (2-5 ans)</option>
            <option value="Senior (5+ ans)">Senior (5+ ans)</option>
          </select>
        </div>

        <!-- Expire le -->
        <div class="form-group-compact span-all">
          <label for="expires_at">Date limite de candidature</label>
          <input type="date" id="expires_at" name="expires_at" [(ngModel)]="job.expires_at">
        </div>
      </div>
    </div>

    <!-- ================= PANNEAU DROIT : DESCRIPTIONS & ACTION ================= -->
    <div class="job-panel-card">
      <div class="panel-inner-title"><i class="bi bi-text-paragraph"></i> Contenu de la fiche de poste</div>
      
      <div class="compact-form-grid vertical-stack">
        <!-- Missions principales -->
        <div class="form-group-compact">
          <label for="missions">Missions principales *</label>
          <textarea id="missions" name="missions_desc" [(ngModel)]="job.missions_desc" rows="4" placeholder="Décrivez les responsabilités quotidiennes et les projets techniques..." required></textarea>
        </div>

        <!-- Profil recherché -->
        <div class="form-group-compact">
          <label for="profile">Profil recherché & Prérequis *</label>
          <textarea id="profile" name="profile_desc" [(ngModel)]="job.profile_desc" rows="4" placeholder="Compétences clés, technologies maîtrisées, soft skills..." required></textarea>
        </div>
      </div>

      <!-- 🔘 BOUTON PREMIUM INTÉGRÉ AU BAS DU PANNEAU DROIT -->
      <div class="form-actions-compact" style="margin-top: 20px;">
        <button type="submit" class="btn-publish-job-compact">
          <i class="bi bi-rocket-takeoff-fill"></i> Diffuser l'annonce
        </button>
      </div>
    </div>

  </form>
</div>
